"""协同进化分组与自适应差分进化算法 / Cooperative Co-evolution Grouping and Adaptive Differential Evolution.此模块实现了 DCCC (Dynamic Cooperative Co-evolution with Contribution) 算法，用于大规模优化问题的分组与优化。它基于 DG2 分解结果进一步划分子空间，并使用 SaNSDE 作为子优化器，动态评估子空间贡献并选择下一轮优化的子空间。This module implements the DCCC (Dynamic Cooperative Co-evolution with Contribution) algorithmfor grouping and optimization of large-scale problems. It further partitions subspaces based onDG2 decomposition, uses SaNSDE as the sub-optimizer, dynamically evaluates subspace contributions,and selects the subspace for the next round of optimization.主要组件 / Main Components:    - DCCC: 算法主类，包含分组构建、子优化器、贡献度评估与选择逻辑。            Main class containing grouping construction, sub-optimizer,            contribution evaluation and selection logic.使用示例 / Usage Example:    >>> from dccc import DCCC    >>> import numpy as np    >>> def sphere(x):    ...     return np.sum(x**2)    >>> info = {'dimension': 100, 'lower': -100, 'upper': 100}    >>> subspaces = {'seps': list(range(50)), 'nonseps': [list(range(50, 100))]}    >>> optimizer = DCCC(sphere, info, subspaces)    >>> best_fitness, history = optimizer.run()    >>> print(f"Best fitness: {best_fitness}")参考 / References:    - [DG2: A faster and more accurate differential grouping for large-scale black-box optimization]    - [SaNSDE: Self-adaptive differential evolution with neighborhood search]"""import loggingfrom typing import Dict, List, Optional, Callable, Any, Union, Tupleimport numpy as npimport numpy.typing as nptfrom scipy.spatial.distance import cdist# 配置日志 / Configure logginglogger = logging.getLogger(__name__)class DCCC:    """    DCCC 算法主类 / DCCC Algorithm Main Class.    该类负责构建分组、运行协同进化优化，并根据子空间的贡献动态选择下一轮优化的子空间。    It constructs groups, runs cooperative co-evolution optimization, and dynamically selects    the subspace for the next round based on contributions.    Attributes:        fun (Callable): 目标函数 / Objective function to minimize.        dim (int): 问题维度 / Problem dimension.        lb (npt.NDArray[np.float64]): 下界数组 / Lower bound array.        ub (npt.NDArray[np.float64]): 上界数组 / Upper bound array.        popsize (int): 种群大小 / Population size.        Max_FEs (int): 最大函数评估次数 / Maximum number of function evaluations.        groups (List[Dict]): 分组列表，每个分组包含索引、贡献度、难度和最大迭代次数。                             List of groups, each containing index, delta, difficulty, max_iter.    """    def __init__(        self,        fun: Callable[[npt.NDArray[np.float64]], float],        info: Dict[str, int],        subspaces: Dict[str, List[List[int]]]    ) -> None:        """        初始化 DCCC 优化器 / Initialize DCCC optimizer.        Args:            fun: 目标函数，接受一维数组并返回适应度值。                 Objective function, accepts a 1D array and returns fitness.            info: 包含问题信息的字典 / Dict containing problem information:                - 'dimension' (int): 问题维度 / Problem dimension.                - 'lower' (float): 下界 / Lower bound.                - 'upper' (float): 上界 / Upper bound.            subspaces: DG2 生成的子空间结构，包含 'seps' 和 'nonseps'。                      Subspace structure from DG2, containing 'seps' and 'nonseps'.                - 'seps' (List[int]): 可分离变量索引 / Separable variable indices.                - 'nonseps' (List[List[int]]): 非可分离变量组列表 / List of non-separable groups.        Raises:            ValueError: 如果信息不完整或维度不匹配 / If info is incomplete or dimensions mismatch.        """        self.fun = fun        self.dim = info['dimension']        self.lb = np.full(self.dim, info['lower'], dtype=np.float64)        self.ub = np.full(self.dim, info['upper'], dtype=np.float64)        self.popsize = 100                     # 种群大小 / Population size        # 根据问题复杂度动态调整最大评估次数 / Adjust max FEs based on problem complexity        self.Max_FEs = int(3e6)                # 最大函数评估次数 / Maximum function evaluations        # 根据子空间信息进一步分组 / Further partition based on subspace info        self.groups = self._build_groups(subspaces)    # ==========================================    # 分组构建 / Group Construction    # ==========================================    def _build_groups(self, subspaces: Dict[str, List[List[int]]]) -> List[Dict[str, Any]]:        """        根据子空间信息构建更细粒度的分组 / Build finer groups from subspace information.        将非分离子空间按块大小 `block_nonsep` 分块，分离子空间按块大小 `block_sep` 分块。        Partitions non-separable subspaces into blocks of size `block_nonsep`,        and separable subspaces into blocks of size `block_sep`.        Args:            subspaces: 包含 'seps' 和 'nonseps' 的字典 / Dict containing 'seps' and 'nonseps'.        Returns:            List[Dict]: 分组列表，每个字典包含：                        List of groups, each dict contains:                - 'index' (npt.NDArray[np.int64]): 变量索引 / Variable indices.                - 'delta' (float): 贡献度累积 / Accumulated contribution.                - 'difficulty' (float): 优化难度 / Optimization difficulty (1 - |correlation|).                - 'max_iter' (int): 每次优化的最大迭代次数 / Max iterations per optimization.        """        groups = []        block_nonsep = 100        block_sep = 20        # 处理非分离子空间 / Process non-separable subspaces        if not subspaces['nonseps']:            # 无非分离变量 / No non-separable variables            dim = len(subspaces['seps'])            for i in range(0, dim, block_nonsep):                groups.append({                    "index": np.arange(i, min(i + block_nonsep, dim), dtype=np.int64),                    "delta": 0.0,                    "difficulty": 1.0,                    "max_iter": 100                })            seps = []                            # 所有变量已划入块 / All variables are now in blocks        else:                                    # 有非分离变量 / Have non-separable variables            for g in subspaces['nonseps']:                g_arr = np.array(g, dtype=np.int64)                dim_g = len(g_arr)                for i in range(0, dim_g, block_nonsep):                    groups.append({                        "index": g_arr[i: min(i + block_nonsep, dim_g)],                        "delta": 0.0,                        "difficulty": 1.0,                        "max_iter": 100                    })            seps = subspaces['seps']             # 剩余分离变量 / Remaining separable variables        # 处理分离子空间 / Process separable subspaces        if seps:            for i in range(0, len(seps), block_sep):                groups.append({                    "index": np.array(seps[i:i + block_sep], dtype=np.int64),                    "delta": 0.0,                    "difficulty": 1.0,                    "max_iter": 100                })        logger.info(f"构建了 {len(groups)} 个分组 / Built {len(groups)} groups")        return groups    # ==========================================    # 种群初始化 / Population Initialization    # ==========================================    def _init_population(self) -> Tuple[npt.NDArray[np.float64], npt.NDArray[np.float64]]:        """        初始化种群 / Initialize population.        在 [lb, ub] 范围内均匀随机生成 `popsize` 个个体，并计算适应度。        Uniformly randomly generate `popsize` individuals within [lb, ub] and evaluate fitness.        Returns:            Tuple[ndarray, ndarray]:                - pop: 种群矩阵，形状 (popsize, dim) / Population matrix, shape (popsize, dim)                - fit: 适应度数组，形状 (popsize,) / Fitness array, shape (popsize,)        """        pop = np.random.uniform(self.lb, self.ub, (self.popsize, self.dim))        fit = np.zeros(self.popsize)        for i in range(self.popsize):            fit[i] = self.fun(pop[i])        return pop, fit    # ==========================================    # 子优化器：SaNSDE / Sub-optimizer: SaNSDE    # ==========================================    def _optimizer(        self,        group: Dict[str, Any],        gpop: npt.NDArray[np.float64],        fit: npt.NDArray[np.float64],        OPTS: Optional[Dict[str, Any]] = None    ) -> Tuple[npt.NDArray[np.float64], npt.NDArray[np.float64], int, Dict[str, Any]]:        """        对单个分组执行 SaNSDE 优化 / Run SaNSDE optimization on a single group.        SaNSDE (Self-adaptive Differential Evolution with Neighborhood Search) 是一种自适应差分进化算法，        它自适应选择变异策略（rand/1 或 current-to-best/2）和缩放因子 F 的分布（正态或柯西），        并自适应调整交叉率 CR。        SaNSDE is a self-adaptive DE that adaptively selects mutation strategy        (rand/1 or current-to-best/2) and the distribution of scaling factor F        (normal or Cauchy), and adaptively adjusts crossover rate CR.        Args:            group: 当前分组信息，必须包含 'index' 和 'max_iter'。                   Current group info, must contain 'index' and 'max_iter'.            gpop: 全局种群矩阵 / Global population matrix, shape (popsize, dim).            fit: 全局适应度数组 / Global fitness array, shape (popsize,).            OPTS: SaNSDE 状态字典，若为 None 则初始化。                  SaNSDE state dict, if None it will be initialized.                  Keys include: 'F', 'linkp', 'l1', 'l2', 'nl1', 'nl2', 'fp',                                'ns1', 'ns2', 'nf1', 'nf2', 'cc_rec', 'f_rec',                                'ccm', 'cc', 'iter'.        Returns:            Tuple containing:                - gpop: 更新后的全局种群 / Updated global population.                - fit: 更新后的适应度 / Updated fitness.                - fes: 本次调用消耗的函数评估次数 / Number of FEs consumed in this call.                - OPTS: 更新后的 SaNSDE 状态 / Updated SaNSDE state.        """        fit_old = fit.copy()                     # 保存旧适应度用于计算贡献 / Save old fitness for contribution        idx = group["index"]                     # 当前分组索引 / Current group indices        D = len(idx)                              # 分组维度 / Group dimension        NP = self.popsize        max_iter = group["max_iter"]        subpop = gpop[:, idx].copy()              # 提取子种群 / Extract sub-population        # ---------- 初始化 / Initialize OPTS ----------        if OPTS is None:            OPTS = {                'F': np.zeros(NP),                # 缩放因子 / Scaling factors                'linkp': 0.5,                     # 选择策略 current-to-best/2 的概率 / Probability of current-to-best/2                'l1': 1, 'l2': 1, 'nl1': 1, 'nl2': 1,   # 策略成功/失败计数器 / Strategy success/failure counters                'fp': 0.5,                         # 选择正态分布生成 F 的概率 / Probability of normal distribution for F                'ns1': 1, 'nf1': 1, 'ns2': 1, 'nf2': 1, # F 分布成功/失败计数器 / F-distribution success/failure counters                'cc_rec': [],                       # 交叉率成功记录 / Successful crossover rates                'f_rec': [],                         # 适应度改进量记录 / Fitness improvement records                'ccm': 0.5,                          # 交叉率均值 / Mean crossover rate                'cc': np.full(NP, 0.5),              # 个体交叉率 / Individual crossover rates                'iter': 0                             # 已迭代次数 / Iterations done            }        # 解包状态字典方便使用 / Unpack state dict for convenience        F = OPTS['F']        linkp = OPTS['linkp']        l1, l2, nl1, nl2 = OPTS['l1'], OPTS['l2'], OPTS['nl1'], OPTS['nl2']        fp = OPTS['fp']        ns1, ns2, nf1, nf2 = OPTS['ns1'], OPTS['ns2'], OPTS['nf1'], OPTS['nf2']        cc_rec, f_rec = OPTS['cc_rec'], OPTS['f_rec']        ccm = OPTS['ccm']        cc = OPTS['cc']        iter_count = OPTS['iter']        subbestmem = subpop[np.argmin(fit), :].copy()  # 当前分组最优个体 / Current best in group        rot = np.arange(NP)                              # 用于索引旋转 / For index rotation        # ---------- 主优化循环 / Main optimization loop ----------        for it in range(max_iter):            fit = fit.ravel()                 # 确保一维 / Ensure 1D            fit_prev = fit.copy()            popold = subpop.copy()            # 保存上一代种群 / Save previous generation            # 生成随机排列用于变异向量选择 / Generate random permutations for mutation vector selection            ind = np.random.permutation(4)            a1 = np.random.permutation(NP)            a2 = a1[np.mod(rot + ind[0], NP)]            a3 = a2[np.mod(rot + ind[1], NP)]            a4 = a3[np.mod(rot + ind[2], NP)]            a5 = a4[np.mod(rot + ind[3], NP)]            pm1, pm2, pm3, pm4, pm5 = popold[a1], popold[a2], popold[a3], popold[a4], popold[a5]            bm = np.tile(subbestmem, (NP, 1))  # 最优个体矩阵 / Best individual matrix            # ----- 自适应交叉率 / Adaptive Crossover Rate -----            if it % 25 == 0 and it != 0 and len(f_rec) > 0:                # 每25代根据历史成功记录更新均值 ccm / Update mean ccm every 25 gens based on success history                ccm = np.sum(np.array(f_rec) * np.array(cc_rec)) / (np.sum(f_rec) + 1e-12)                cc_rec.clear()                f_rec.clear()            if it % 5 == 0:                # 每5代从正态分布 N(ccm, 0.1) 重新生成所有个体的交叉率 / Regenerate CR for all individuals every 5 gens                samples = np.random.normal(ccm, 0.1, 3 * NP)                valid = samples[(samples > 0) & (samples < 1)]                if len(valid) >= NP:                    cc = valid[:NP]                else:                    cc = np.clip(np.random.normal(ccm, 0.1, NP), 0, 1)            # ----- 自适应缩放因子 F / Adaptive Scaling Factor F -----            fst1 = np.random.rand(NP) <= fp          # 选择正态分布 / Choose normal distribution            fst2 = ~fst1                              # 选择柯西分布 / Choose Cauchy distribution            if np.sum(fst1) > 0:                F[fst1] = np.abs(np.random.normal(0.5, 0.3, np.sum(fst1)))            if np.sum(fst2) > 0:                # 用两个独立正态的比值近似柯西分布 / Approximate Cauchy by ratio of two normals                F[fst2] = np.abs(np.random.normal(0, 1, np.sum(fst2)) /                                 (np.random.normal(0, 1, np.sum(fst2)) + 1e-12))            F = np.clip(F, 0, 100)                   # 限制过大值 / Clip extreme values            # ----- 生成二项式交叉掩码 / Generate Binomial Crossover Mask -----            mui = np.random.rand(NP, D) < cc[:, None]            for i in range(NP):                if not np.any(mui[i]):                    mui[i, np.random.randint(D)] = True   # 确保每个个体至少有一个维度交叉 / Ensure at least one dimension            mpo = ~mui            # ----- 选择变异策略 / Select Mutation Strategy -----            aaa = np.random.rand(NP) <= linkp        # True: current-to-best/2, False: rand/1            aindex = np.where(~aaa)[0]                # 使用 rand/1 的个体 / Individuals using rand/1            bindex = np.where(aaa)[0]                  # 使用 current-to-best/2 的个体 / Individuals using current-to-best/2            ui = np.zeros_like(popold)            if len(bindex) > 0:                ui[bindex] = (popold[bindex] +                              F[bindex, None] * (bm[bindex] - popold[bindex]) +                              F[bindex, None] * (pm1[bindex] - pm2[bindex] + pm3[bindex] - pm4[bindex]))                ui[bindex] = popold[bindex] * mpo[bindex] + ui[bindex] * mui[bindex]            if len(aindex) > 0:                ui[aindex] = pm3[aindex] + F[aindex, None] * (pm1[aindex] - pm2[aindex])                ui[aindex] = popold[aindex] * mpo[aindex] + ui[aindex] * mui[aindex]            # ----- 边界约束处理 / Bound Handling -----            ui = np.clip(ui, self.lb[idx], self.ub[idx])            # ----- 评估试验个体 / Evaluate Trial Individuals -----            trial_subpop = ui.copy()            trial_gpop = gpop.copy()            trial_gpop[:, idx] = trial_subpop            trial_fit = np.array([self.fun(indv) for indv in trial_gpop]).ravel()            fes_this_iter = NP                       # 本次迭代消耗的评估次数 / FEs consumed this iteration            # ----- 选择 / Selection -----            trial_fit = trial_fit.ravel()            fit_prev = fit_prev.ravel()            improve_mask = (trial_fit <= fit_prev).ravel()          # 非劣改进 / Non-worse improvement            strict_improve_mask = (trial_fit < fit_prev).ravel()    # 严格改进 / Strict improvement            fit[improve_mask] = trial_fit[improve_mask]            gpop[improve_mask, :] = trial_gpop[improve_mask, :]            # ----- 更新策略计数器 / Update Strategy Counters -----            # 策略选择计数器 / Strategy selection counters            l1 += np.sum(aaa[improve_mask])          # current-to-best/2 成功次数 / Success of current-to-best/2            l2 += np.sum(~aaa[improve_mask])         # rand/1 成功次数 / Success of rand/1            nl1 += np.sum(aaa[~improve_mask])        # current-to-best/2 失败次数 / Failure of current-to-best/2            nl2 += np.sum(~aaa[~improve_mask])       # rand/1 失败次数 / Failure of rand/1            # F 分布计数器 / F distribution counters            ns1 += np.sum(fst1[improve_mask])        # 正态分布 F 成功次数 / Success of normal F            ns2 += np.sum(fst2[improve_mask])        # 柯西分布 F 成功次数 / Success of Cauchy F            nf1 += np.sum(fst1[~improve_mask])       # 正态分布 F 失败次数 / Failure of normal F            nf2 += np.sum(fst2[~improve_mask])       # 柯西分布 F 失败次数 / Failure of Cauchy F            # 记录严格改进个体的交叉率和改进量 / Record CR and improvement for strictly improved individuals            if np.any(strict_improve_mask):                cc_rec.extend(cc[strict_improve_mask].tolist())                f_rec.extend((fit_prev[strict_improve_mask] - trial_fit[strict_improve_mask]).tolist())            # ----- 更新分组最优个体 / Update Group Best -----            subbestmem = gpop[np.argmin(fit), :][idx].copy()            subpop = gpop[:, idx].copy()             # 刷新子种群 / Refresh sub-population            # ----- 每50代更新策略概率 / Update Strategy Probabilities Every 50 Gens -----            if (it + 1) % 50 == 0:                # 更新 linkp (策略选择概率) / Update linkp (strategy selection probability)                l1_ratio = l1 / (l1 + nl1 + 1e-12)                l2_ratio = l2 / (l2 + nl2 + 1e-12)                linkp = l1_ratio / (l1_ratio + l2_ratio + 1e-12)                l1 = l2 = nl1 = nl2 = 1              # 重置计数器 / Reset counters                # 更新 fp (F 分布选择概率) / Update fp (F distribution probability)                fp = (ns1 * (ns2 + nf2)) / (ns2 * (ns1 + nf1) + ns1 * (ns2 + nf2) + 1e-12)                ns1 = nf1 = ns2 = nf2 = 1             # 重置计数器 / Reset counters        # ---------- 保存更新后的状态 / Save updated state ----------        OPTS.update({            'F': F,            'linkp': linkp,            'l1': l1, 'l2': l2, 'nl1': nl1, 'nl2': nl2,            'fp': fp,            'ns1': ns1, 'nf1': nf1, 'ns2': ns2, 'nf2': nf2,            'cc_rec': cc_rec, 'f_rec': f_rec,            'ccm': ccm,            'cc': cc,            'iter': iter_count + max_iter        })        # 计算贡献度 delta (适应度总提升) / Compute contribution delta (total fitness improvement)        group["delta"] = 0.8 * group["delta"] + np.sum(np.maximum(0, fit_old - fit))        return gpop, fit, fes_this_iter * max_iter, OPTS    # ==========================================    # 分组难度评估 / Group Difficulty Evaluation    # ==========================================    def _evaluate_difficulty(self, group: Dict[str, Any], pop: npt.NDArray[np.float64], fit: npt.NDArray[np.float64]) -> None:        """        评估当前分组的优化难度 / Evaluate the optimization difficulty of a group.        难度定义为 1 - |correlation|，其中 correlation 是种群个体适应度与其到最优个体距离的 Pearson 相关系数。        Difficulty is defined as 1 - |correlation|, where correlation is the Pearson correlation        between fitness and distance to the best individual in the group.        Args:            group: 分组字典，将更新 'difficulty' 键。                   Group dict, its 'difficulty' key will be updated.            pop: 全局种群 / Global population.            fit: 全局适应度 / Global fitness.        """        idx = group["index"]        sub = pop[:, idx]        bestid = np.argmin(fit)        dis = cdist(sub, sub[bestid].reshape(1, -1)).flatten()        fit_bar = np.mean(fit)        dis_bar = np.mean(dis)        numerator = np.sum((fit - fit_bar) * (dis - dis_bar))        denominator = (np.sqrt(np.sum((fit - fit_bar) ** 2)) *                       np.sqrt(np.sum((dis - dis_bar) ** 2)) + 1e-12)        r = numerator / denominator        group["difficulty"] = 1 - abs(r)    # ==========================================    # 分组选择器 / Group Selector    # ==========================================    def _selector(self) -> int:        """        根据贡献度和难度选择下一个优化的分组 / Select the next group based on delta and difficulty.        选择 score = delta * difficulty 最大的分组；若所有 delta 为零则随机选择。        Select the group with highest score = delta * difficulty; if all deltas are zero, choose randomly.        Returns:            int: 被选中的分组索引 / Index of the selected group.        """        deltas = np.array([float(g["delta"]) for g in self.groups])        if np.sum(deltas) == 0:            return np.random.randint(len(self.groups))        scores = [g["delta"] * g["difficulty"] for g in self.groups]        idx = int(np.argmax(scores))        return idx    # ==========================================    # 主运行流程 / Main Run Loop    # ==========================================    def run(self) -> Tuple[float, List[float]]:        """        执行 DCCC 主优化循环 / Execute the main DCCC optimization loop.        1. 初始化种群 / Initialize population.        2. 当评估次数未达上限时循环 / Loop until max FEs reached:            - 以 0.3 概率随机选择分组，否则根据贡献度选择。              With 0.3 probability randomly choose a group, otherwise use contribution-based selection.            - 调用 _optimizer 优化该分组 / Call _optimizer on that group.            - 调用 _evaluate_difficulty 更新分组难度 / Update group difficulty.            - 记录全局最优适应度 / Record global best fitness.        Returns:            Tuple[float, List[float]]:                - best_fitness: 最终全局最优适应度 / Final global best fitness.                - fitness_curve: 每轮迭代后的全局最优适应度历史 / History of global best fitness after each round.        """        gpop, fit = self._init_population()        FEs = self.popsize        bestfit = np.min(fit)        OPTS = None        iteration = 0        fitness_curve = [bestfit]        print(f"{'Iter':>5} | {'Subspace':>8} | {'Dim':>4} | {'BestFit':>15} | {'Delta':>10}")        print("-" * 60)        while FEs < self.Max_FEs:            fit_old = fit.copy()            # 分组选择 / Group selection            if np.random.rand() < 0.3:                gid = np.random.randint(len(self.groups))            else:                gid = self._selector()            group = self.groups[gid]            # 优化所选分组 / Optimize selected group            gpop, fit, fes, OPTS = self._optimizer(group, gpop, fit, OPTS)            FEs += fes            # 评估分组难度 / Evaluate group difficulty            self._evaluate_difficulty(group, gpop, fit)            # 更新全局最优 / Update global best            bestfit = np.min(fit)            fitness_curve.append(bestfit)            delta_change = np.sum(np.maximum(0, fit_old - fit))            print(f"{iteration:5d} | {gid:8d} | {len(group['index']):4d} | {bestfit:15.6e} | {delta_change:10.3e}")            iteration += 1        print("-" * 60)        print(f"Finished. Best fitness: {bestfit:.6e}")        logger.info(f"Optimization finished after {FEs} FEs, best fitness: {bestfit:.6e}")        return bestfit, fitness_curve